const raw = parseInt(msg.payload, 10);

// Valider : 0–2000 W/m² (plage capteur)
if (isNaN(raw) || raw < 0 || raw > 2000) {
    node.warn('Valeur irradiance invalide : ' + msg.payload);
    node.status({fill:'red', shape:'ring', text:'Valeur invalide : ' + msg.payload});
    return null;
}

global.set('irradiance_wm2', raw);

// Statut visuel selon intensité solaire
let fill = 'grey';
if (raw === 0)        fill = 'grey';
else if (raw < 200)   fill = 'yellow';
else if (raw < 600)   fill = 'yellow';
else                  fill = 'green';

node.status({fill, shape: 'dot', text: raw + ' W/m²'});

msg.payload = raw;
return msg;
